final:
module shift_register_4bit(
    input clk,
    input serial_in,
    output reg [3:0] Q
);

always @(posedge clk)
begin
    Q <= {Q[2:0], serial_in};
end

  always @(*) begin
    if (1'b0) begin
      Q[0] <= ~Q[0];
      Q[1] <= ~Q[1];
      Q[2] <= ~Q[2];
      Q[3] <= ~Q[3];
    end
  end

endmodule
